/**
 * safeDivide
 *
 * Specification summary (also in README):
 * - Function: safeDivide(numerator, denominator, options?)
 * - Inputs:
 *    - numerator: number (finite)
 *    - denominator: number (finite)
 *    - options?: { onZero?: 'throw' | 'null' | 'infinity' }
 * - Output: number | null (null only possible when options.onZero === 'null')
 * - Default behavior: options.onZero defaults to 'throw' => throws RangeError on division by zero
 * - Edge behaviors:
 *    - onZero === 'null' => return null when denominator === 0
 *    - onZero === 'infinity' => return signed Infinity based on numerator sign; if numerator === 0 => NaN
 * - Invalid inputs (non-finite numbers) => throw TypeError
 */

export type OnZeroBehavior = 'throw' | 'null' | 'infinity';

export interface SafeDivideOptions {
  onZero?: OnZeroBehavior;
}

export function safeDivide(numerator: number, denominator: number, options?: SafeDivideOptions): number | null {
  const onZero: OnZeroBehavior = options?.onZero ?? 'throw';

  // Validate inputs: must be finite numbers
  if (!Number.isFinite(numerator) || !Number.isFinite(denominator)) {
    throw new TypeError('Inputs must be finite numbers');
  }

  if (denominator === 0) {
    if (onZero === 'throw') {
      throw new RangeError('Division by zero');
    }

    if (onZero === 'null') {
      return null;
    }

    // onZero === 'infinity'
    if (numerator === 0) return NaN;
    return numerator > 0 ? Infinity : -Infinity;
  }

  return numerator / denominator;
}

export default safeDivide;

import { safeDivide } from '../src/index';

describe('safeDivide', () => {
  test('returns normal quotient for non-zero denominator', () => {
    expect(safeDivide(6, 3)).toBe(2);
    expect(safeDivide(-9, 3)).toBe(-3);
  });

  test('throws RangeError by default when denominator is zero', () => {
    expect(() => safeDivide(1, 0)).toThrow(RangeError);
  });

  test('returns null when onZero is "null"', () => {
    expect(safeDivide(1, 0, { onZero: 'null' })).toBeNull();
  });

  test('returns signed infinity when onZero is "infinity"', () => {
    expect(safeDivide(5, 0, { onZero: 'infinity' })).toBe(Infinity);
    expect(safeDivide(-5, 0, { onZero: 'infinity' })).toBe(-Infinity);
    // 0/0 with infinity policy -> NaN
    const res = safeDivide(0, 0, { onZero: 'infinity' });
    expect(Number.isNaN(res as number)).toBe(true);
  });

  test('throws TypeError for non-finite inputs', () => {
    expect(() => safeDivide(NaN, 1)).toThrow(TypeError);
    expect(() => safeDivide(1, Infinity)).toThrow(TypeError);
  });
});
